import json

import requests


class TestJSONPathConstrainedMixin:
    """Mixin providing test cases for the json_path output constraint.

    Expects ``self.base_url`` (str) to be set by the concrete test class.
    """

    def _run_json_path(self, json_path, prompt=None, max_new_tokens=128):
        if prompt is None:
            prompt = "Generate a JSON object:"
        response = requests.post(
            self.base_url + "/generate",
            json={
                "text": prompt,
                "sampling_params": {
                    "temperature": 0,
                    "max_new_tokens": max_new_tokens,
                    "json_path": json_path,
                },
                "stream": False,
            },
        )
        ret = response.json()
        print(json.dumps(ret))
        print("=" * 100)
        return ret

    # ------------------------------------------------------------------
    # Positive tests
    # ------------------------------------------------------------------

    def test_json_path_simple(self):
        """$.name — output must be a JSON object containing a 'name' key."""
        ret = self._run_json_path(
            "$.name",
            prompt="Generate a JSON object with a name field about Paris:",
        )
        obj = json.loads(ret["text"])
        self.assertIn("name", obj)

    def test_json_path_nested(self):
        """$.store.book[*].author — nested path with array of objects."""
        ret = self._run_json_path(
            "$.store.book[*].author",
            prompt="Generate a bookstore JSON with books and their authors:",
            max_new_tokens=256,
        )
        obj = json.loads(ret["text"])
        self.assertIn("store", obj)
        self.assertIn("book", obj["store"])
        self.assertIsInstance(obj["store"]["book"], list)
        for book in obj["store"]["book"]:
            self.assertIn("author", book)

    def test_json_path_bracket_notation(self):
        """$['title'] bracket notation — functionally same as $.title."""
        ret = self._run_json_path(
            "$['title']",
            prompt="Generate a JSON object with a title field:",
        )
        obj = json.loads(ret["text"])
        self.assertIn("title", obj)

    def test_json_path_array_field(self):
        """$.items[*] — output must have an 'items' key that is an array."""
        ret = self._run_json_path(
            "$.items[*]",
            prompt="Generate a JSON object with an items list:",
        )
        obj = json.loads(ret["text"])
        self.assertIn("items", obj)
        self.assertIsInstance(obj["items"], list)

    def test_json_path_numeric_index(self):
        """$.data[0].value — numeric index treated same as wildcard."""
        ret = self._run_json_path(
            "$.data[0].value",
            prompt="Generate a JSON object with a data array whose elements have a value field:",
        )
        obj = json.loads(ret["text"])
        self.assertIn("data", obj)
        self.assertIsInstance(obj["data"], list)
        for item in obj["data"]:
            self.assertIn("value", item)

    def test_mix_json_path_and_no_constraint(self):
        """Mixing constrained and unconstrained requests concurrently."""
        from concurrent.futures import ThreadPoolExecutor

        paths = [None, None, "$.name", "$.name"] * 5

        def _run(path):
            if path is None:
                return requests.post(
                    self.base_url + "/generate",
                    json={
                        "text": "Say hello:",
                        "sampling_params": {"temperature": 0, "max_new_tokens": 16},
                    },
                ).json()
            return self._run_json_path(path)

        with ThreadPoolExecutor(len(paths)) as executor:
            results = list(executor.map(_run, paths))

        for path, ret in zip(paths, results):
            if path is not None:
                obj = json.loads(ret["text"])
                self.assertIn("name", obj)

    # ------------------------------------------------------------------
    # Negative / error-handling tests
    # ------------------------------------------------------------------

    def test_json_path_invalid_recursive_descent(self):
        """$..field uses recursive descent which is unsupported — must abort."""
        response = requests.post(
            self.base_url + "/generate",
            json={
                "text": "Generate something:",
                "sampling_params": {
                    "temperature": 0,
                    "max_new_tokens": 64,
                    "json_path": "$..field",
                },
            },
        )
        ret = response.json()
        # The request must either be HTTP 400 or finish with abort reason.
        if response.status_code == 200:
            finish_reason = (
                ret.get("meta_info", {}).get("finish_reason") or {}
            )
            self.assertEqual(
                finish_reason.get("type"),
                "abort",
                f"Expected abort finish_reason, got: {ret}",
            )

    def test_json_path_invalid_filter_expression(self):
        """$.field[?(@.x>5)] uses filter expressions which are unsupported."""
        response = requests.post(
            self.base_url + "/generate",
            json={
                "text": "Generate something:",
                "sampling_params": {
                    "temperature": 0,
                    "max_new_tokens": 64,
                    "json_path": "$.field[?(@.x>5)]",
                },
            },
        )
        ret = response.json()
        if response.status_code == 200:
            finish_reason = (
                ret.get("meta_info", {}).get("finish_reason") or {}
            )
            self.assertEqual(
                finish_reason.get("type"),
                "abort",
                f"Expected abort finish_reason, got: {ret}",
            )

